import itertools

def find_numbers():
    target_sum = 4444
    min_diff = float('inf')
    result = None

    for p1 in itertools.permutations(range(1, 9), 4):
        for p2 in itertools.permutations(range(1, 9), 4):
            if set(p1).isdisjoint(set(p2)):
                num1 = int(''.join(map(str, p1)))
                num2 = int(''.join(map(str, p2)))
                sum_num = num1 + num2
                diff = abs(target_sum - sum_num)
                if diff < min_diff:
                    min_diff = diff
                    result = (num1, num2)

    return result

